{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-reconnect-connection-placeholder-ordering-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "当前围绕已选中物流 liquid-out-2 的下游断开问题生成候选提案：为该出口物流添加一个待确认的下游连接占位，而不是直接重连或创建新对象。",
      "issues": [
        {
          "title": "Liquid Product 缺少下游消费者或出口汇",
          "detail": "诊断指出 stream liquid-out-2 未连接到任何 downstream consumer 或 export sink，且最新快照显示拓扑无效。",
          "severity": "error",
          "target": {
            "type": "stream",
            "id": "liquid-out-2"
          },
          "citations": [
            "diag-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 Liquid Product 添加下游连接占位",
          "target": {
            "type": "stream",
            "id": "liquid-out-2"
          },
          "rationale": "该物流已有上游 source_unit_id=separator-2，但缺少下游消费者或出口汇。由于当前输入中没有可直接连接的目标单元或出口对象，建议仅添加一个需人工确认的 connection_placeholder，用于标记需要选择或创建下游 export sink/consumer。",
          "patch": {
            "connection_placeholder": {
              "stream_id": "liquid-out-2",
              "missing_side": "downstream",
              "expected_connection_role": "consumer_or_export_sink",
              "source_unit_id": "separator-2",
              "note": "Select an existing downstream consumer/export sink or create one before applying a topology-changing connection."
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        }
      ],
      "confidence": 0.86
    }
  ]
}
